import{_ as u,C as h,o as t,c as d,a2 as r,b as n,w as a,a as i,E as s,a3 as c,j as l}from"./chunks/framework.Bj6f68Cg.js";const S=JSON.parse('{"title":"Mock LLM Server","description":"","frontmatter":{},"headers":[],"relativePath":"projects/mock-llm.md","filePath":"projects/mock-llm.md"}'),p={name:"projects/mock-llm.md"};function m(k,e,A,g,b,_){const o=h("Mermaid");return t(),d("div",null,[e[2]||(e[2]=r('<h1 id="mock-llm-server" tabindex="-1">Mock LLM Server <a class="header-anchor" href="#mock-llm-server" aria-label="Permalink to &quot;Mock LLM Server&quot;">​</a></h1><p>로컬 개발 환경 및 CI/CD 파이프라인에서 실제 LLM API 호출 없이도 초고속으로 대형 언어 모델의 응답 스펙을 모사(Mocking)해주는 테스트용 에뮬레이터 서버입니다.</p><h2 id="📌-status-repository" tabindex="-1">📌 Status &amp; Repository <a class="header-anchor" href="#📌-status-repository" aria-label="Permalink to &quot;📌 Status &amp; Repository&quot;">​</a></h2><ul><li><strong>상태</strong>: <code>Stable</code></li><li><strong>저장소 공개 범위</strong>: 비공개 구현 저장소</li><li><strong>라이선스</strong>: MIT</li><li><strong>주요 언어</strong>: Rust, Go</li></ul><hr><h2 id="_1-problem" tabindex="-1">1. Problem <a class="header-anchor" href="#_1-problem" aria-label="Permalink to &quot;1. Problem&quot;">​</a></h2><p>AI 에이전트나 Gateway 서비스를 테스트할 때, 실제 외부 LLM API(OpenAI, Claude 등)를 실시간 호출하여 검증하면 다음과 같은 문제가 따릅니다:</p><ol><li>호출 시마다 비용이 크게 누적됩니다.</li><li>테스트 한 건당 최소 수초의 지연시간이 발생하여 전체 CI 빌드 파이프라인이 심각하게 지연됩니다.</li><li>API 호출 한도(Rate Limit)나 네트워크 유실 시 테스트 결과가 기각되는 불안정성이 유발됩니다.</li></ol><h2 id="_2-why-i-built-it" tabindex="-1">2. Why I Built It <a class="header-anchor" href="#_2-why-i-built-it" aria-label="Permalink to &quot;2. Why I Built It&quot;">​</a></h2><p>OpenAI 및 vLLM 규격의 HTTP API 응답 스키마를 100% 모방하되, 실제 거대 연산(추론)을 돌리지 않고 사전에 설계된 템플릿 텍스트 또는 스트리밍 토큰 청크를 즉각 밀어주어, 단 1ms 미만의 지연시간 내에 신뢰할 수 있는 모사 응답을 제공하는 고속 검증 서버를 구축했습니다.</p><h2 id="_3-scope" tabindex="-1">3. Scope <a class="header-anchor" href="#_3-scope" aria-label="Permalink to &quot;3. Scope&quot;">​</a></h2><ul><li><code>/v1/chat/completions</code> 및 <code>/v1/embeddings</code> API 스키마 모사</li><li>스트리밍 응답(<code>stream: true</code>)의 Server-Sent Events(SSE) 프로토콜 토큰 전송 시뮬레이션</li><li>특정 키워드 수신 시 지정된 지연시간(Latency simulation) 또는 의도된 HTTP 오류 코드(429, 502 등) 반환 기능</li><li>Pydantic 규격에 호환되는 더미 토큰 생성</li></ul><hr><h2 id="_4-architecture" tabindex="-1">4. Architecture <a class="header-anchor" href="#_4-architecture" aria-label="Permalink to &quot;4. Architecture&quot;">​</a></h2>',14)),(t(),n(c,null,{default:a(()=>[s(o,{id:"mermaid-90",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20Client%5B%22AI%20Application%20%2F%20Agent%22%5D%20--%3E%7CAPI%20Call%7C%20Mock%5B%22Mock%20LLM%20Server%22%5D%0A%20%20%20%20subgraph%20Engine%20%5B%22Request%20Handling%20Engine%22%5D%0A%20%20%20%20%20%20%20%20Mock%20--%3E%20Router%5B%22Route%20Switch%20(chat%2Fembeddings)%22%5D%0A%20%20%20%20%20%20%20%20Router%20--%3E%20RuleEngine%5B%22Rule-based%20Response%20Matcher%22%5D%0A%20%20%20%20%20%20%20%20RuleEngine%20--%3E%20Template%5B%22Static%20Response%20Templates%22%5D%0A%20%20%20%20%20%20%20%20RuleEngine%20--%3E%20Streamer%5B%22SSE%20Token%20Chunk%20Generator%22%5D%0A%20%20%20%20end%0A%20%20%20%20Mock%20--%3E%7CHTTP%20Status%7C%20Client%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[i(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=l("hr",null,null,-1)),e[4]||(e[4]=l("h2",{id:"_5-request-flow",tabindex:"-1"},[i("5. Request Flow "),l("a",{class:"header-anchor",href:"#_5-request-flow","aria-label":'Permalink to "5. Request Flow"'},"​")],-1)),(t(),n(c,null,{default:a(()=>[s(o,{id:"mermaid-95",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20autonumber%0A%20%20%20%20participant%20Client%20as%20Client%20Agent%0A%20%20%20%20participant%20Mock%20as%20Mock%20LLM%20Server%0A%0A%20%20%20%20Client-%3E%3EMock%3A%20POST%20%2Fv1%2Fchat%2Fcompletions%20(with%20Prompt)%0A%20%20%20%20Mock-%3E%3EMock%3A%20Match%20prompt%20against%20simulation%20rules%0A%20%20%20%20alt%20Prompt%20contains%20Simulate%20Error%20502%0A%20%20%20%20%20%20%20%20Mock--%3E%3EClient%3A%20502%20Bad%20Gateway%0A%20%20%20%20else%20stream%20is%20true%0A%20%20%20%20%20%20%20%20loop%20Each%20Token%20Chunk%0A%20%20%20%20%20%20%20%20%20%20%20%20Mock--%3E%3EClient%3A%20data%3A%20%7B%22choices%22%3A%20%5B%7B%22delta%22%3A%20%7B%22content%22%3A%20%22Token%22%7D%7D%5D%7D%0A%20%20%20%20%20%20%20%20end%0A%20%20%20%20%20%20%20%20Mock--%3E%3EClient%3A%20data%3A%20%5BDONE%5D%0A%20%20%20%20else%20Standard%20Completion%0A%20%20%20%20%20%20%20%20Mock--%3E%3EClient%3A%20200%20OK%20(Clean%20Mock%20JSON)%0A%20%20%20%20end%0A"})]),fallback:a(()=>[...e[1]||(e[1]=[i(" Loading... ",-1)])]),_:1})),e[5]||(e[5]=r(`<hr><h2 id="_6-key-design-decisions" tabindex="-1">6. Key Design Decisions <a class="header-anchor" href="#_6-key-design-decisions" aria-label="Permalink to &quot;6. Key Design Decisions&quot;">​</a></h2><ul><li><strong>경량 무의존성 단일 바이너리</strong>: 실제 파이썬 기반 추론 스택(vLLM)을 전혀 올리지 않기 때문에, 수 메가바이트 크기의 가볍고 빠른 단일 바이너리로 구동할 수 있어 CI/CD 컨테이너 내에서 단 10ms 만에 즉시 실행됩니다.</li><li><strong>룰 기반 예외 상황 주입</strong>: 단순히 더미 텍스트만 주는 것이 아니라, &quot;특정 프롬프트가 들어올 시 10초 딜레이&quot;, &quot;특정 헤더 누락 시 401 반환&quot; 등 복잡한 에지 케이스 테스트 시나리오를 구성할 수 있도록 룰 엔진을 도입했습니다.</li></ul><h2 id="_7-security-considerations" tabindex="-1">7. Security Considerations <a class="header-anchor" href="#_7-security-considerations" aria-label="Permalink to &quot;7. Security Considerations&quot;">​</a></h2><ul><li>로컬 또는 격리된 CI 파이프라인 내부에서만 바인딩되어 외부 트래픽 유입에 무관하며, 내부망 밖으로 실 데이터가 흘러나갈 가능성을 원천적으로 배제합니다.</li></ul><h2 id="_8-observability" tabindex="-1">8. Observability <a class="header-anchor" href="#_8-observability" aria-label="Permalink to &quot;8. Observability&quot;">​</a></h2><ul><li>매 API 쿼리 및 매칭된 모사 규칙에 대한 로그를 표준 출력으로 명확하게 덤프하여 개발자가 어떤 목업 룰이 매칭되었는지 확인하기 쉽도록 제공합니다.</li></ul><h2 id="_9-technology-stack" tabindex="-1">9. Technology Stack <a class="header-anchor" href="#_9-technology-stack" aria-label="Permalink to &quot;9. Technology Stack&quot;">​</a></h2><ul><li><strong>Engine</strong>: Rust (Axum / Tokio) 또는 Go (Gin)</li><li><strong>Format</strong>: JSON, Server-Sent Events</li></ul><hr><h2 id="_10-running-locally" tabindex="-1">10. Running Locally <a class="header-anchor" href="#_10-running-locally" aria-label="Permalink to &quot;10. Running Locally&quot;">​</a></h2><p>로컬에서 8080 포트로 목업 서버를 즉시 띄울 수 있습니다.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 로컬 백엔드 서버 가동 (OpenAI API 모사 포트: 8080)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mock-llm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8080</span></span></code></pre></div><h2 id="_11-current-limitations" tabindex="-1">11. Current Limitations <a class="header-anchor" href="#_11-current-limitations" aria-label="Permalink to &quot;11. Current Limitations&quot;">​</a></h2><ul><li>사전에 고정 정의되거나 정해진 단순 규칙 이외의 복잡한 추론 로직(자유도 높은 문맥 응답)은 흉내 낼 수 없어, 고차원 에이전트의 판단 논리 루프 검증에는 어려움이 있습니다.</li></ul><h2 id="_12-next-steps" tabindex="-1">12. Next Steps <a class="header-anchor" href="#_12-next-steps" aria-label="Permalink to &quot;12. Next Steps&quot;">​</a></h2><ul><li>OpenAI Assistant API 스펙 추가 모사 및 다중 대화 세션 컨텍스트 저장 시뮬레이션 지원.</li></ul>`,17))])}const y=u(p,[["render",m]]);export{S as __pageData,y as default};
